1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	const HIGH_ENCHANTMENT_RATE = 0.3;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	
12	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	};
18	
19	type Item = {
20	  type: string;
21	  material?: string;
22	  enchantment?: number;
23	  cursed?: boolean;
24	};
25	type Step = { op: "quote"; items: Item[] };
26	type Customer = { yearsWithMHPCO: number };
27	type Scenario = { customer: Customer; steps: Step[] };
28	
29	const componentGroupPremium = (count: number): number =>
30	  count === COMPONENT_BLOCK_SIZE
31	    ? COMPONENT_BLOCK_PREMIUM
32	    : count * COMPONENT_BASE_PREMIUM;
33	
34	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
35	
36	const isHighEnchantment = (item: Item): boolean =>
37	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
38	
39	const qualifiesForFirstInsurance = (item: Item, isSingleItemPolicy: boolean): boolean =>
40	  isSingleItemPolicy && !!item.cursed && !isHighEnchantment(item);
41	
42	const surchargeRates = (item: Item, isSingleItemPolicy: boolean): number[] => [
43	  item.cursed ? CURSE_SURCHARGE_RATE : 0,
44	  isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0,
45	  qualifiesForFirstInsurance(item, isSingleItemPolicy) ? FIRST_INSURANCE_RATE : 0,
46	];
47	
48	const mainItemPremium = (item: Item, isSingleItemPolicy: boolean): number => {
49	  const base = BASE_PREMIUM_BY_TYPE[item.type];
50	  const totalRate = surchargeRates(item, isSingleItemPolicy).reduce((a, b) => a + b, 1);
51	  return base * totalRate;
52	};
53	
54	const countByType = (items: Item[]): Map<string, number> =>
55	  items.reduce(
56	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
57	    new Map<string, number>(),
58	  );
59	
60	const sumComponentPremiums = (components: Item[]): number =>
61	  [...countByType(components).values()]
62	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
63	
64	const sumItemPremiums = (items: Item[]): number => {
65	  const mains = items.filter(isMainItem);
66	  const components = items.filter((i) => !isMainItem(i));
67	  const isSingleItemPolicy = items.length === 1;
68	  const mainsSum = mains.reduce((sum, item) => sum + mainItemPremium(item, isSingleItemPolicy), 0);
69	  return mainsSum + sumComponentPremiums(components);
70	};
71	
72	const policyWideRate = (customer: Customer): number =>
73	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -LOYALTY_DISCOUNT_RATE : 0;
74	
75	const quotePremiumFor = (step: Step, customer: Customer): { premium: number } => ({
76	  premium: sumItemPremiums(step.items) * (1 + policyWideRate(customer)) + PROCESSING_FEE,
77	});
78	
79	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
80	  results: scenario.steps.map((step) => quotePremiumFor(step, scenario.customer)),
81	});
